```class Solution {
public:
    string resultingString(string s) {
        while (true) {
            int i = 0;
            while (i < s.length() - 1) {
                if (abs(s[i] - s[i + 1]) == 1) {
                    s.erase(i, 2);
                    break;
                }
                i++;
            }
            if (i == s.length() - 1) break;
        }
        return s;
    }
};
